"""offlinai_latex — Local offline LaTeX → SVG rendering for iOS.

Uses pdftex (cross-compiled C library via lib-tex) + dvisvgm to convert
LaTeX expressions to SVG files. Falls back to Cairo text rendering if
pdftex is unavailable.

Architecture:
  LaTeX source → pdftex (via ctypes) → DVI → dvisvgm → SVG
  Fallback: LaTeX → Unicode conversion → Cairo text_path → SVG
"""

import os
import sys
import ctypes
import tempfile
import pathlib
import threading
import hashlib

__version__ = "1.0.1"

# pdftex's C library has gigabytes of static/global state and was written
# as a single-shot command-line program. Calling dllpdftexmain() a second
# time in the same process corrupts the heap and crashes with
# EXC_BAD_ACCESS after a handful of calls — unacceptable for manim
# scenes that render 20+ math expressions back-to-back.
#
# On iOS the Cairo text-path fallback is used by default (looks less
# pretty than pdftex-rendered math but never crashes). Users who really
# want pdftex can opt in with OFFLINAI_LATEX_USE_PDFTEX=1. The single
# lock below + SVG cache below then make repeated calls at least
# serialize + deduplicate, reducing crash risk.
_USE_PDFTEX = os.environ.get("OFFLINAI_LATEX_USE_PDFTEX", "") == "1"
_pdftex_lock = threading.Lock()
_svg_cache: dict[str, str] = {}   # hash(expr) → svg_path
_pdftex_failed_once = False       # after any pdftex failure, never try again

# Find the app bundle paths
_this_dir = os.path.dirname(os.path.abspath(__file__))
_app_dir = os.path.dirname(os.path.dirname(os.path.dirname(_this_dir)))
_fw_dir = os.path.join(_app_dir, "Frameworks")
_latex_dir = os.path.join(_app_dir, "Frameworks", "latex")
_texmf_dir = os.path.join(_app_dir, "Frameworks", "latex", "texmf")

# Try alternate paths for iOS app bundle
if not os.path.isdir(_fw_dir):
    _bundle = os.path.dirname(os.path.dirname(_this_dir))
    _fw_dir = os.path.join(_bundle, "Frameworks")
    _latex_dir = os.path.join(_fw_dir, "latex")
    _texmf_dir = os.path.join(_latex_dir, "texmf")

_pdftex_available = False
_pdftex_lib = None
_kpathsea_lib = None


def _load_pdftex():
    """Load pdftex via ctypes. ios_system is already initialized by Swift."""
    global _pdftex_available, _pdftex_lib, _kpathsea_lib

    # ios_system is loaded by Swift at app startup — just verify it's there
    for lib_name in ["ios_system", "kpathsea", "pdftex"]:
        fw_path = os.path.join(_fw_dir, f"{lib_name}.framework", lib_name)
        if os.path.exists(fw_path):
            try:
                lib = ctypes.CDLL(fw_path, mode=ctypes.RTLD_GLOBAL)
                if lib_name == "pdftex":
                    _pdftex_lib = lib
                elif lib_name == "kpathsea":
                    _kpathsea_lib = lib
            except OSError as e:
                print(f"[latex] Failed to load {lib_name}: {e}")

    _pdftex_available = _pdftex_lib is not None
    return _pdftex_available


# The pdftex C library's static state corrupts after ONE invocation
# in this process (documented "non-reentrancy"). Track it module-wide
# and refuse to call dllpdftexmain a second time in the same session.
_pdftex_called_this_session = False

# WASM path first-run flag (separate from the native-path one above).
# Flipped to True after the first compile_tex() call completes — lets
# the shell UI skip the "~10 s format warm-up" banner on later calls.
_wasm_first_run_done = False

# Safety kill-switch: the bundled pdftex.xcframework is holzschu/lib-tex
# v1.40.20 from 2019. Calling dllpdftexmain crashes with
# EXC_BAD_ACCESS @ 0x68 — an unresolved bug
# (https://github.com/holzschu/lib-tex/issues/1) — because modern
# latex.ltx + expl3 use pdftex primitives added after 1.40.20.
# Neither pthread isolation nor ini-mode wrappers fix this.
# Until the bundled xcframework is rebuilt from current lib-tex master
# (or replaced by SwiftLaTeX WASM), we refuse to run the C library at
# all and tell the user what's up. Set
# OFFLINAI_LATEX_FORCE_NATIVE=1 to override if you're debugging.
_NATIVE_PDFTEX_KNOWN_BROKEN = os.environ.get(
    "OFFLINAI_LATEX_FORCE_NATIVE", "") != "1"


def compile_tex(tex_source, output_dir=None, engine="pdftex"):
    """Compile a .tex file using pdftex via ctypes.

    On iOS, the bundled pdftex is v1.40.20 and there's no way to ship
    matching-version .fmt files (host TeX Live is 1.40.27+). Instead
    we invoke pdftex in ini mode with a wrapper that inlines
    ``\\input latex.ltx`` AND neutralises the ``\\dump`` primitive so
    processing continues into the user's document in the same call.
    Slower than a pre-built .fmt (the kernel reloads from sources
    every time, ~5-10 s), but avoids the version-mismatch crash.

    Because pdftex corrupts its static C state after one call, this
    function refuses to run a second time in the same app session.
    Users must restart the app between compiles.

    Parameters
    ----------
    tex_source : str | path-like
        Path to an existing .tex file (or raw LaTeX source).
    output_dir : str, optional
        Where to write artifacts. Created if missing.
    engine : str
        "pdflatex" (PDF output) | "latex" (DVI output) |
        "pdftex" (plain TeX, no kernel preload) |
        "xelatex" (falls back to pdflatex).

    Returns
    -------
    str | None
        Path to the produced PDF/DVI, or None on failure.
    """
    global _pdftex_called_this_session

    # Preferred path on iOS: dispatch to the SwiftLaTeX WASM engine
    # via a signal file. Swift's LaTeXEngine picks up the request,
    # runs real pdflatex inside a hidden WKWebView (no native-lib
    # crash, reentrant, unlimited compiles per session), writes the
    # resulting PDF back to disk, and drops a "done" marker for us
    # to poll. This bypasses the crash-prone dllpdftexmain entirely.
    if not _NATIVE_PDFTEX_KNOWN_BROKEN:
        # User forced native path — fall through to old ctypes code.
        pass
    else:
        if output_dir is None:
            output_dir = tempfile.mkdtemp(prefix="offlinai_tex_")
        os.makedirs(output_dir, exist_ok=True)
        if not os.path.exists(tex_source):
            tex_file = os.path.join(output_dir, "input.tex")
            with open(tex_file, 'w') as f:
                f.write(tex_source)
        else:
            tex_file = os.path.abspath(tex_source)

        stem = os.path.splitext(os.path.basename(tex_file))[0]
        pdf_path = os.path.join(output_dir, stem + ".pdf")
        done_path = os.path.join(tempfile.gettempdir(),
                                 "latex_signals", "compile_doc_done.txt")

        # Clear any stale markers. compile_progress.log must be cleared
        # BEFORE we write the request file or read its size — Swift
        # truncates + rewrites it for each compile, and on warm runs
        # the prior compile's size (e.g. 2 KB) would be our starting
        # offset, so all of Swift's new output at offsets 0…K < 2 KB
        # would be invisible to our `size <= offset` poll check.
        signal_dir_early = os.path.join(tempfile.gettempdir(), "latex_signals")
        for p in (pdf_path, done_path,
                  os.path.join(output_dir, stem + ".log"),
                  os.path.join(signal_dir_early, "compile_progress.log")):
            try: os.remove(p)
            except OSError: pass

        signal_dir = os.path.join(tempfile.gettempdir(), "latex_signals")
        os.makedirs(signal_dir, exist_ok=True)
        # Line 4 tells Swift which engine the user invoked (pdflatex vs
        # xelatex vs latex). The busytex dispatch on the Swift side
        # maps this to the right driver (pdftex_bibtex8 vs
        # xetex_bibtex8_dvipdfmx). SwiftLaTeX ignores it (its WASM
        # only does pdftex).
        req_path = os.path.join(signal_dir, "compile_doc_request.txt")
        with open(req_path, "w", encoding="utf-8") as f:
            f.write(f"{tex_file}\n{pdf_path}\n{stem}\n{engine}\n")

        # Poll for completion. Simple docs (amsmath etc.) take 2-8 s.
        # Beamer + pgf + tikz on WASM pdftex 1.40.20 is inherently
        # slow — even after files are all fetched, the compute phase
        # (beamer preamble processing, expl3 macro expansion, PDF
        # page tree building) can take 2-4 minutes on first run.
        # 300 s timeout is large enough for cold beamer without
        # hanging the shell indefinitely if truly stuck.
        #
        # While polling, tail the Swift-side progress file so the user
        # sees "fetched 125 texmf files (last: pgfcore.sty)" etc. in
        # real time instead of staring at a frozen prompt.
        progress_path = os.path.join(signal_dir, "compile_progress.log")
        import time as _time
        # Track a byte offset instead of holding an open fh — Python's
        # buffered reader on a regular file doesn't always see writes a
        # separate process has appended (the OS may not refresh the
        # buffer). Re-open each poll reading from the tracked offset is
        # 100% reliable. Start offset = current size of file if it exists
        # so prior-compile lines aren't echoed.
        # Always start at 0 — we deleted the prior compile's file
        # above, so whatever Swift creates is the current run's output.
        # Reading os.path.getsize here and using it as a starting
        # offset caused a race on warm compiles (size reflected the
        # pre-delete prior-run size; all Swift's new lines landed at
        # offset < size and were skipped → user saw only heartbeats).
        progress_offset = 0

        start_time = _time.time()
        # 600 s (10 min) — heavy beamer+TikZ docs can genuinely take
        # that long on a 2019 WASM pdftex when doing complex macro
        # expansion. Ctrl+C breaks the wait early if you need to.
        deadline = start_time + 600.0
        last_output_time = start_time          # when we last printed something
        last_heartbeat_time = start_time       # when we last emitted a keepalive
        def drain_progress():
            nonlocal progress_offset
            printed = False
            try:
                size = os.path.getsize(progress_path)
            except OSError:
                return False
            if size <= progress_offset:
                return False
            try:
                with open(progress_path, "rb") as fh:
                    fh.seek(progress_offset)
                    data = fh.read()
                    progress_offset = fh.tell()
            except OSError:
                return False
            try:
                chunk = data.decode("utf-8", errors="replace")
            except Exception:
                return False
            for line in chunk.splitlines():
                if line.strip():
                    print(f"  \033[2;36m[latex]\033[0m {line}", flush=True)
                    printed = True
            return printed
        # Drain & heartbeat loop. Every poll we:
        #  1. Re-open the progress file, seek to the last-read offset,
        #     print any new lines. Re-opening each time dodges the
        #     Python-buffered-reader problem (pre-existing fh might not
        #     reflect bytes Swift appended from another process context).
        #  2. If nothing has come through for 5 s, emit a dim heartbeat
        #     so the user knows the shell is alive.
        aborted = False
        try:
            while _time.time() < deadline:
                if drain_progress():
                    last_output_time = _time.time()
                now = _time.time()
                if (now - last_output_time) >= 5.0 \
                   and (now - last_heartbeat_time) >= 5.0:
                    elapsed = int(now - start_time)
                    print(f"  \033[2;90m[latex]\033[0m "
                          f"still compiling ({elapsed}s elapsed — "
                          f"engine busy, no output for "
                          f"{int(now - last_output_time)}s)",
                          flush=True)
                    last_heartbeat_time = now
                if os.path.exists(done_path):
                    break
                _time.sleep(0.2)
        except KeyboardInterrupt:
            aborted = True
            print(f"\n  \033[2;33m[latex]\033[0m aborted by user "
                  f"(Ctrl+C) — WASM engine keeps running in the "
                  f"background until it settles; next pdflatex call "
                  f"will queue behind it.", flush=True)
        # Final drain so the last milestone ("compile OK — ...") shows.
        drain_progress()
        if aborted:
            return None

        if not os.path.exists(done_path):
            print("[latex] compile timed out after 600s (WASM engine stuck?)")
            return None

        # Read status from the marker
        try:
            with open(done_path, "r", encoding="utf-8") as f:
                lines = f.read().splitlines()
            status = int(lines[0]) if lines else -1
            message = lines[1] if len(lines) > 1 else ""
        except (OSError, ValueError):
            status, message = -1, "couldn't read done marker"
        try: os.remove(done_path)
        except OSError: pass

        # Track first-run so the shell can drop the "~10 s warm-up"
        # banner on subsequent compiles. Success OR failure counts —
        # either way the format is cached on the Swift side after
        # the first pass through.
        globals()["_wasm_first_run_done"] = True

        if status == 0 and os.path.exists(pdf_path):
            return pdf_path

        print(f"[latex] compile failed (status={status}): {message}")
        log_path = os.path.splitext(pdf_path)[0] + ".log"
        if os.path.exists(log_path):
            print(f"[latex] log: {log_path}")
            # Show the first TeX error if any
            try:
                with open(log_path, "r", encoding="utf-8",
                          errors="replace") as f:
                    log_text = f.read()
                import re as _re
                m = _re.search(r"^(!\s.*?)$", log_text, _re.MULTILINE)
                if m:
                    snippet = log_text[m.start():m.start() + 600]
                    for line in snippet.splitlines()[:6]:
                        print(f"  {line}")
            except OSError:
                pass
        # If no TeX-level log OR the compile died before pdftex even
        # ran (status != 0 AND log is missing / empty / only has
        # "can't find format"), dump the engine init log so the user
        # can see preload-time errors (e.g. compileFormat failing).
        init_log = os.path.join(signal_dir, "engine_init.log")
        log_empty_or_fmt_err = (
            not os.path.exists(log_path)
            or os.path.getsize(log_path) < 200
            or "can't find the format file" in (log_text if 'log_text' in dir() else "")
        )
        if log_empty_or_fmt_err and os.path.exists(init_log):
            print(f"[latex] engine init log: {init_log}")
            try:
                with open(init_log, "r", encoding="utf-8",
                          errors="replace") as f:
                    init_content = f.read()
                # Show last 50 lines
                for line in init_content.splitlines()[-50:]:
                    if line.strip():
                        print(f"  {line}")
            except OSError:
                pass
        return None

    # ── Below: native ctypes path (only reached if
    # OFFLINAI_LATEX_FORCE_NATIVE=1 was set). Kept for debugging.
    if _pdftex_called_this_session:
        print("[latex] pdftex has already been invoked once this session.")
        print("[latex] Restart the app and try again — pdftex's static")
        print("[latex] state can't be reset without a fresh process.")
        return None

    if not _pdftex_available:
        _load_pdftex()
    if not _pdftex_available:
        print("[latex] pdftex C library not loaded")
        return None

    if output_dir is None:
        output_dir = tempfile.mkdtemp(prefix="offlinai_tex_")
    os.makedirs(output_dir, exist_ok=True)

    if not os.path.exists(tex_source):
        tex_file = os.path.join(output_dir, "input.tex")
        with open(tex_file, 'w') as f:
            f.write(tex_source)
    else:
        tex_file = os.path.abspath(tex_source)

    # Env for TeX/kpathsea
    os.environ['TEXMFCNF'] = os.path.join(_texmf_dir, 'web2c')
    os.environ['TEXMFDIST'] = _texmf_dir
    os.environ['TEXMF'] = _texmf_dir
    # Writable cache for any pdftex-side scratch (.aux, .log sidecars)
    cache = os.path.expanduser("~/Documents/.offlinai_latex_cache")
    os.makedirs(cache, exist_ok=True)
    os.environ['TEXMFVAR'] = cache
    os.environ['TEXMFCACHE'] = cache

    engine_l = (engine or "pdflatex").lower()
    if engine_l == "xelatex":
        engine_l = "pdflatex"
    if engine_l not in ("pdftex", "pdflatex", "latex"):
        engine_l = "pdflatex"

    # Need latex.ltx preloaded for anything but plain TeX. Rather than
    # use a pre-built .fmt (version mismatch → crash), we run pdftex
    # in ini mode against a tiny wrapper that inlines the kernel +
    # the user's source. One pdftex call, no .fmt dependency.
    #
    # Critical wrapper tricks:
    #   • `\let\dump\relax` BEFORE loading latex.ltx — the kernel's
    #     final line is `\dump` (meant to write the .fmt and exit).
    #     Neutering it lets processing continue into the user's doc.
    #   • `\pdfoutput=1` before the kernel so PDF (not DVI) is produced.
    #     Set it even for `latex` engine (DVI); the kernel's l3backend
    #     reads this to pick dvips vs pdftex driver.
    #   • `\nonstopmode` is re-asserted AFTER the kernel loads because
    #     latex.ltx ends with `\errorstopmode`, which would otherwise
    #     make every TeX error wait for keyboard input (fatal in a GUI).
    wants_latex_kernel = (engine_l in ("pdflatex", "latex"))
    want_pdf_output = (engine_l == "pdflatex")

    stem = os.path.splitext(os.path.basename(tex_file))[0]
    if wants_latex_kernel:
        wrapper = os.path.join(output_dir, f"__{stem}_wrapper.tex")
        with open(wrapper, "w", encoding="utf-8") as f:
            f.write("\\let\\dump\\relax\n")
            if want_pdf_output:
                f.write("\\pdfoutput=1\n")
            else:
                f.write("\\pdfoutput=0\n")
            f.write("\\input latex.ltx\\relax\n")
            f.write("\\nonstopmode\n")
            # Force Latin Modern fonts for the whole document. The
            # bundle ships lm.pfb files (~6 MB) but not cm-super, so
            # text-companion (TS1) glyphs referenced by hyperref /
            # textcomp resolve to `tcrm1095.pfb` which doesn't exist
            # → "Font at 72 not found" and the PDF fails. Latin
            # Modern has full TS1 coverage via `lmodern.sty` and
            # renders visually identical to Computer Modern.
            f.write("\\RequirePackage{lmodern}\n")
            f.write(f"\\input {{{tex_file}}}\n")
            f.write("\\end\n")
        input_file = wrapper
        # Job name should be the USER's doc name, not the wrapper, so
        # output lands at `<stem>.pdf` (where the user expects it).
        # But pdftex reads args[0] as the program name to pick the
        # engine defaults — keep that as "pdflatex" / "latex".
    else:
        input_file = tex_file

    try:
        func = _pdftex_lib.dllpdftexmain
        func.restype = ctypes.c_int
        func.argtypes = [ctypes.c_int, ctypes.POINTER(ctypes.c_char_p)]

        # pdftex's LaTeX kernel requires e-TeX extensions
        # (`\protected`, `\detokenize`, etc.); without `-etex` the
        # kernel aborts with "LaTeX requires e-TeX". `pdflatex` as a
        # command name usually implies it, but `dllpdftexmain` sees
        # only the bytes we pass, so add the flag explicitly.
        args = [engine_l.encode()]
        if wants_latex_kernel:
            args.append(b"-etex")
            args.append(b"-ini")
        args.extend([
            b"--interaction=nonstopmode",
            f"--output-directory={output_dir}".encode(),
            f"--jobname={stem}".encode(),
            input_file.encode(),
        ])
        argc = len(args)
        argv = (ctypes.c_char_p * argc)(*args)

        # Mark called BEFORE the C call — if it segfaults, we want the
        # flag set so subsequent attempts short-circuit cleanly.
        _pdftex_called_this_session = True

        # ── pthread isolation for the C call ────────────────────────
        # dllpdftexmain touches thousands of file-scope C globals that
        # were never designed for repeated invocation. Calling it on
        # the Python main thread reuses stale state from prior runs
        # (even if we've gated at the Python level — setjmp/longjmp
        # slots and stdio buffers outlive our module). The a-Shell
        # app, the one iOS project that runs pdftex reliably, always
        # dispatches to a freshly created pthread via ios_system.m's
        # pthread_create/join pattern. Python's threading.Thread maps
        # 1:1 to pthread_create, so running on a dedicated thread
        # gives pdftex the clean stack + TLS slots it expects.
        result = [None]
        exc = [None]

        def _run():
            try:
                result[0] = func(argc, argv)
            except BaseException as e:  # ctypes can raise SystemExit
                exc[0] = e

        t = threading.Thread(target=_run, name="pdftex-isolated")
        t.start()
        t.join()

        if exc[0] is not None:
            print(f"[latex] pdftex C-library call raised: "
                  f"{type(exc[0]).__name__}: {exc[0]}")
            return None
        rc = result[0]

        # Clean up wrapper + TeX-system scratch files we wrote into the
        # user's directory. We keep <stem>.pdf/.dvi/.aux/.log because
        # those are the expected LaTeX artifacts, but the wrapper and
        # texsys.aux are internal plumbing the user shouldn't see.
        if wants_latex_kernel:
            for junk in (input_file, os.path.join(output_dir, "texsys.aux")):
                try:
                    os.remove(junk)
                except OSError:
                    pass

        for ext in (".pdf", ".dvi"):
            candidate = os.path.join(output_dir, stem + ext)
            if os.path.exists(candidate):
                if rc not in (0, None):
                    print(f"[latex] pdftex exit={rc} but produced {ext[1:]}")
                return candidate
        print(f"[latex] pdftex exit={rc}; no .pdf/.dvi was produced")
    except BaseException as e:
        print(f"[latex] compile_tex wrapper raised: "
              f"{type(e).__name__}: {e}")

    return None


def _autowrap_math_in_text(latex):
    """Auto-wrap math-only macros that appear inside ``\\text{...}`` with
    ``$...$`` so the expression compiles in our xelatex+fontspec setup.

    amsmath's ``\\text{...}`` is text-mode and does NOT auto-switch back to
    math for nested commands like ``\\underbrace``, ``\\boxed``, ``\\frac``,
    ``\\sqrt``, ``\\sum``, ``\\frac``. A manim user writes
    ``\\text{A 三角形 + \\underbrace{3 \\times 2}_{...}}`` expecting it to
    work — and on stock LaTeX with package overrides like ctex it sometimes
    does — but our pipeline is plain amsmath + fontspec, so we get
    ``! Missing $ inserted``.

    This walker fixes the common case automatically: scan every ``\\text{}``
    block (with proper brace matching), find each known math command + its
    braced argument(s) + any subsequent ``_{...}`` / ``^{...}``, and wrap
    that whole chunk in ``$...$``. Recurses into nested ``\\text{}`` so
    deeply-nested cases like the user's
    ``\\underbrace{...}_{\\text{... \\underbrace{...}_{\\text{... \\boxed{...}}}}}``
    are fully resolved.

    Existing ``$...$`` regions are detected and left alone (so we don't
    double-wrap user-supplied math fragments).
    """
    import re as _re

    MATH_CMDS = (
        "underbrace", "overbrace", "boxed",
        "frac", "dfrac", "tfrac", "binom", "dbinom", "tbinom",
        "sqrt",
        "sum", "prod", "int", "oint", "iint", "iiint",
        "bigcup", "bigcap", "bigvee", "bigwedge", "biguplus", "bigsqcup",
        "hat", "bar", "vec", "tilde", "dot", "ddot",
        "widehat", "widetilde", "overline", "underline",
        "mathbb", "mathbf", "mathcal", "mathfrak", "mathsf",
        "mathtt", "mathit", "mathrm", "operatorname",
    )
    cmd_re = _re.compile(r"\\(" + "|".join(MATH_CMDS) + r")\b")
    text_re = _re.compile(r"\\text\s*\{")

    def find_brace_end(s, brace_pos):
        depth = 0
        n = len(s)
        i = brace_pos
        while i < n:
            c = s[i]
            if c == "\\" and i + 1 < n:
                i += 2
                continue
            if c == "{":
                depth += 1
            elif c == "}":
                depth -= 1
                if depth == 0:
                    return i
            i += 1
        return -1

    def consume_arg_run(s, i):
        """From position i, consume any number of `{...}`, `_{...}`, `^{...}`,
        single-token `_x` / `^x` tail-attached to a math command. Returns
        the index just past the run."""
        n = len(s)
        while i < n:
            c = s[i]
            if c == "{":
                end = find_brace_end(s, i)
                if end < 0:
                    return i
                i = end + 1
            elif c in "_^" and i + 1 < n:
                j = i + 1
                if s[j] == "{":
                    end = find_brace_end(s, j)
                    if end < 0:
                        return i
                    i = end + 1
                elif s[j] == "\\":
                    m = _re.match(r"\\[A-Za-z]+", s[j:])
                    i = j + (m.end() if m else 1)
                else:
                    i = j + 1
            else:
                break
        return i

    def skip_dollar(s, i):
        """If s[i] == '$', return index just past the matching close `$`.
        Handles `$$...$$` (display math) and escaped `\\$`."""
        n = len(s)
        if i >= n or s[i] != "$":
            return i
        # display math?
        display = i + 1 < n and s[i + 1] == "$"
        j = i + (2 if display else 1)
        while j < n:
            if s[j] == "\\" and j + 1 < n:
                j += 2
                continue
            if s[j] == "$":
                if display:
                    if j + 1 < n and s[j + 1] == "$":
                        return j + 2
                    j += 1
                    continue
                return j + 1
            j += 1
        return n

    def process_text_content(content):
        """Walk text-mode content character by character; wrap math fragments
        in `$...$` and recurse into nested `\\text{...}`. Forward scan so
        existing `$...$` regions are detected and skipped verbatim."""
        out = []
        i = 0
        n = len(content)
        while i < n:
            c = content[i]
            if c == "$":
                end = skip_dollar(content, i)
                out.append(content[i:end])
                i = end
                continue
            m = text_re.match(content, i)
            if m:
                content_start = m.end()
                end = find_brace_end(content, content_start - 1)
                if end < 0:
                    out.append(content[i:])
                    break
                inner = content[content_start:end]
                out.append(content[i:content_start])  # \text{
                out.append(process_text_content(inner))
                out.append("}")
                i = end + 1
                continue
            m = cmd_re.match(content, i)
            if m:
                cmd_end = m.end()
                full_end = consume_arg_run(content, cmd_end)
                inner_math = content[i:full_end]
                # Wrapped chunk is now math mode; recurse so any nested
                # \text{...} inside its args / subscripts is processed too.
                inner_math = process_top(inner_math)
                out.append("$" + inner_math + "$")
                i = full_end
                continue
            out.append(c)
            i += 1
        return "".join(out)

    def process_top(s):
        """Walk math-mode content character by character. Only `\\text{...}`
        blocks need their contents auto-wrapped. Existing `$...$` (which
        switches BACK to text inside math, e.g. `\\text` typeset) is
        skipped verbatim."""
        out = []
        i = 0
        n = len(s)
        while i < n:
            c = s[i]
            if c == "$":
                end = skip_dollar(s, i)
                out.append(s[i:end])
                i = end
                continue
            m = text_re.match(s, i)
            if m:
                content_start = m.end()
                end = find_brace_end(s, content_start - 1)
                if end < 0:
                    out.append(s[i:])
                    break
                inner = s[content_start:end]
                out.append(s[i:content_start])  # \text{
                out.append(process_text_content(inner))
                out.append("}")
                i = end + 1
                continue
            out.append(c)
            i += 1
        return "".join(out)

    return process_top(latex)


def _try_busytex_math(expression, svg_path, timeout=300.0):
    """Compile a math expression through Swift's BusyTeX engine (real
    xelatex + xeCJK + ctex packages → PDF → high-DPI PNG → SVG with
    embedded <image>).

    Returns ("ok", "") on success, or ("fail", reason) where ``reason``
    is the message from Swift's done marker (e.g. ``"xelatex failed"``,
    ``"compile watchdog tripped"``, ``"PDF→PNG render failed"``). Caller
    surfaces this verbatim rather than silently degrading to SwiftMath
    or Cairo — that silent degrade was the source of the
    "renders as broken/dvi-looking placeholder" symptom we kept chasing.
    """
    import time as _time

    signal_dir = os.path.join(tempfile.gettempdir(), "latex_signals")
    os.makedirs(signal_dir, exist_ok=True)
    request_id = hashlib.sha256(expression.encode("utf-8")).hexdigest()[:16]
    signal_file = os.path.join(signal_dir, "compile_math_request.txt")
    done_file = os.path.join(signal_dir, f"math_done_{request_id}.txt")

    try:
        os.unlink(done_file)
    except OSError:
        pass

    payload = f"{request_id}\n{svg_path}\nFFFFFF\n{expression}\n"
    try:
        with open(signal_file, "w", encoding="utf-8") as f:
            f.write(payload)
    except OSError as e:
        return ("fail", f"signal write failed: {e}")

    start = _time.time()
    while _time.time() - start < timeout:
        if os.path.exists(done_file):
            status_line = "-99"
            message_line = ""
            try:
                with open(done_file, "r", encoding="utf-8") as f:
                    status_line = f.readline().strip()
                    message_line = f.readline().strip()
            except OSError as e:
                message_line = f"could not read done marker: {e}"
            try:
                os.unlink(done_file)
            except OSError:
                pass
            if status_line == "0" and os.path.exists(str(svg_path)):
                return ("ok", "")
            return ("fail", f"status={status_line} {message_line}".strip())
        _time.sleep(0.05)
    return ("fail", f"no done marker after {timeout:.0f}s (Swift hung?)")


def tex_to_svg(expression, svg_path=None, tex_template_body=None):
    """Convert a LaTeX expression to SVG.

    On iOS, defaults to the Cairo text-path fallback (fast, safe, no
    native crashes). Set OFFLINAI_LATEX_USE_PDFTEX=1 to route through
    the real pdftex C library — pretty, but pdftex is not re-entrant
    and will crash the app after a handful of calls in the same
    process. Use only for one-off LaTeX previews, never for manim
    scenes with dozens of math expressions.

    Parameters
    ----------
    expression : str
        LaTeX expression (e.g., "E = mc^2")
    svg_path : str or Path, optional
        Output SVG file path. Auto-generated if not specified.
    tex_template_body : str, optional
        Full .tex file content. If None, wraps expression in minimal template.

    Returns
    -------
    pathlib.Path
        Path to the generated SVG file.
    """
    global _pdftex_failed_once

    if svg_path is None:
        h = hashlib.md5(expression.encode()).hexdigest()[:12]
        # v7 = route through Swift SwiftMath engine first (real Computer
        #      Modern math fonts, dvisvgm-quality output) before
        #      falling back to Cairo sans-serif.
        # v6..v2 = iterative Cairo-fallback improvements.
        svg_path = os.path.join(tempfile.gettempdir(), f"tex_v7_{h}.svg")
    svg_path = pathlib.Path(svg_path)

    # ── Cache — same expression, same SVG. Massively important for manim
    # scenes where the same formula gets re-rendered in every frame.
    # Validate cached SVGs have either <path> (SwiftMath/Cairo output)
    # or <image> (BusyTeX → PNG-in-SVG output) before reusing — a stale
    # broken SVG (single <rect>, no glyph data) was the cause of the
    # "last MathTex shows just dvi" symptom.
    def _svg_has_renderable(p: str) -> bool:
        try:
            with open(p, "rb") as _f:
                head = _f.read(8192).decode("utf-8", errors="ignore")
            return "<svg" in head and ("<path" in head or "<image" in head)
        except OSError:
            return False

    cache_key = hashlib.sha256(expression.encode("utf-8")).hexdigest()
    cached = _svg_cache.get(cache_key)
    if cached and os.path.exists(cached):
        if _svg_has_renderable(cached):
            if str(svg_path) != cached:
                try:
                    import shutil as _sh
                    _sh.copyfile(cached, str(svg_path))
                except OSError:
                    pass
            return svg_path
        # Stale/broken cached SVG — drop it and re-render.
        _svg_cache.pop(cache_key, None)
        try:
            os.unlink(cached)
        except OSError:
            pass
    if svg_path.exists() and svg_path.stat().st_size > 50:
        if _svg_has_renderable(str(svg_path)):
            _svg_cache[cache_key] = str(svg_path)
            return svg_path
        try:
            os.unlink(str(svg_path))
        except OSError:
            pass

    # ── Preferred path #1: Swift BusyTeX (real xelatex + xeCJK) ─────
    # When the expression has CJK in \text{...} OR uses macros that
    # SwiftMath can't render (\underbrace, \boxed, \overrightarrow,
    # \xrightarrow, multi-line align, complex \displaystyle constructs),
    # ship to BusyTeX which compiles real LaTeX → PDF. Swift then
    # rasterises the PDF page to a high-DPI PNG and embeds it in a
    # single-<image> SVG that manim's patched svg_mobject loader
    # produces an ImageMobject from.
    #
    # Why this path exists: SwiftMath ships only Latin Modern math
    # glyphs — anything outside that (CJK, AMS extensions like
    # \underbrace, color math, \boxed) emits a single <rect> placeholder
    # and renders as an empty box in the manim video. BusyTeX is real
    # TeX Live (TL 2023, pdftex 1.40.25 + xetex), so anything that
    # compiles on a desktop also compiles here.
    _busytex_macros_re = (
        r"\\(?:underbrace|overbrace|underline|overline|"
        r"boxed|cancel|xrightarrow|xleftarrow|"
        r"overrightarrow|overleftarrow|tag|"
        r"begin\{(?:cases|align\*?|aligned|matrix|pmatrix|bmatrix|"
        r"vmatrix|smallmatrix|gathered|split)\})"
    )
    _has_cjk_for_routing = any(
        0x3000 <= ord(_c) <= 0x9FFF
        or 0xAC00 <= ord(_c) <= 0xD7AF
        or 0xF900 <= ord(_c) <= 0xFAFF
        or 0xFF00 <= ord(_c) <= 0xFFEF
        for _c in expression
    )
    import re as _re
    _has_busytex_macro = bool(_re.search(_busytex_macros_re, expression))
    _force_busytex = os.environ.get("OFFLINAI_LATEX_FORCE_BUSYTEX", "") == "1"
    _disable_busytex = os.environ.get("OFFLINAI_LATEX_DISABLE_BUSYTEX", "") == "1"
    _route_busytex = (_has_cjk_for_routing or _has_busytex_macro
                      or _force_busytex) and not _disable_busytex
    if _route_busytex:
        # Strip manim's `\special{dvisvgm:raw <g id='unique000'>}` markers
        # before handing the expression to xelatex. They're a hint to the
        # desktop dvisvgm driver for substring-group extraction; xelatex
        # parses the HTML inside the `\special{...}` and dies with a
        # status-1 ("xelatex failed") because of the literal `<` and `>`.
        # That cascade was the source of the "dvi" / "dvisvgm" text the
        # user kept seeing in the rendered video — the broken Cairo
        # fallback was stripping commands but leaving the special's
        # argument visible.
        busytex_expr = _re.sub(r"\\special\{[^}]*\}", "", expression)
        # Auto-wrap math-only commands inside \text{} with $...$ so manim
        # scripts that mix CJK labels with \underbrace / \boxed / \frac
        # / \sqrt / \sum etc. (a common pattern in Chinese math
        # textbooks) compile without `! Missing $ inserted`.
        busytex_expr = _autowrap_math_in_text(busytex_expr)
        ok, reason = _try_busytex_math(busytex_expr, svg_path)
        if ok == "ok":
            _svg_cache[cache_key] = str(svg_path)
            return svg_path
        # Pull the xelatex log Swift writes next to the SVG and surface
        # it so the user sees the actual TeX error (e.g. "Missing $",
        # "Undefined control sequence", "Font not found"), not just
        # "status=1 xelatex failed".
        log_path = os.path.splitext(str(svg_path))[0] + ".latex.log"
        log_excerpt = ""
        try:
            with open(log_path, "r", encoding="utf-8", errors="replace") as f:
                full_log = f.read()
            # xelatex prints the actionable error after a line beginning
            # with `!`. Grab those lines + the next 4 (TeX shows context
            # over multiple lines) and the last 600 chars as a fallback.
            err_lines = []
            log_lines = full_log.splitlines()
            for i, ln in enumerate(log_lines):
                if ln.startswith("!"):
                    err_lines.extend(log_lines[i:i + 5])
            if err_lines:
                log_excerpt = "\n".join(err_lines)[:1000]
            else:
                log_excerpt = full_log[-600:]
        except OSError:
            log_excerpt = "<no log file at " + log_path + ">"
        msg = f"BusyTeX failed: {reason}"
        print(f"[latex] {msg}\n[latex log]\n{log_excerpt}\n[latex] expr: {busytex_expr[:200]!r}", flush=True)
        _write_error_svg(str(svg_path), f"{msg}\n--- xelatex log ---\n{log_excerpt}", busytex_expr)
        raise RuntimeError(
            f"{msg}\nexpression: {busytex_expr!r}\n"
            f"--- xelatex log ---\n{log_excerpt}"
        )

    # ── Path 2: SwiftMath (Latin Modern only, fast). ──
    # Reaches here only if the expression has no CJK and no BusyTeX-only
    # macros. SwiftMath either produces a real `<path>` SVG or fails;
    # we no longer fall through to Cairo on failure.
    import re
    clean_expr = re.sub(r"\\special\{[^}]*\}", '', expression).strip()
    clean_expr = re.sub(r'\\begin\{align\*?\}', '', clean_expr)
    clean_expr = re.sub(r'\\end\{align\*?\}', '', clean_expr)
    clean_expr = clean_expr.strip()

    import time as _time
    signal_dir = os.path.join(tempfile.gettempdir(), "latex_signals")
    os.makedirs(signal_dir, exist_ok=True)
    signal_file = os.path.join(signal_dir, "compile_request.txt")
    try:
        with open(signal_file, "w", encoding="utf-8") as f:
            f.write(f"{clean_expr}\n{svg_path}\n")
    except OSError as e:
        msg = f"SwiftMath signal write failed: {e}"
        print(f"[latex] {msg} | expr: {expression[:120]!r}", flush=True)
        _write_error_svg(str(svg_path), msg, expression)
        raise RuntimeError(f"{msg}\nexpression: {expression!r}")

    deadline = _time.time() + 5.0
    last_head = ""
    while _time.time() < deadline:
        if svg_path.exists() and svg_path.stat().st_size > 100:
            try:
                last_head = svg_path.read_text(encoding="utf-8",
                                               errors="ignore")[:4096]
                if "<path" in last_head and "<svg" in last_head:
                    _svg_cache[cache_key] = str(svg_path)
                    return svg_path
            except OSError:
                pass
        _time.sleep(0.02)

    # SwiftMath produced nothing usable within the deadline. Don't fall
    # through to Cairo — surface the failure so we can fix the real cause.
    diagnostic = f"SwiftMath returned no <path> within 5s (head[:200]={last_head[:200]!r})"
    print(f"[latex] {diagnostic} | expr: {clean_expr[:120]!r}", flush=True)
    _write_error_svg(str(svg_path), diagnostic, clean_expr)
    raise RuntimeError(f"{diagnostic}\nexpression: {clean_expr!r}")


def _write_error_svg(svg_path, error_message, expression):
    """Emit a bright-red error SVG so the user can SEE the failure in the
    rendered video, instead of getting a silent fallback that paints over
    the bug. Lines wrap to ~80 chars and there's no upper line limit —
    if the error is long, the box just gets taller.
    """
    import html as _html
    text = f"LaTeX render error: {error_message}\nexpression: {expression}"
    safe = _html.escape(text)
    # Crude word-wrap so long messages don't get clipped at the edge.
    wrapped = []
    for line in safe.split("\n"):
        while len(line) > 80:
            wrapped.append(line[:80])
            line = line[80:]
        wrapped.append(line)
    line_h = 14
    height = max(40, line_h * (len(wrapped) + 1))
    tspans = "\n".join(
        f'<tspan x="4" dy="{"1.2em" if i else 0}">{l}</tspan>'
        for i, l in enumerate(wrapped)
    )
    svg = (
        f'<?xml version="1.0" encoding="UTF-8"?>\n'
        f'<svg xmlns="http://www.w3.org/2000/svg" '
        f'width="640" height="{height}" viewBox="0 0 640 {height}">\n'
        f'  <rect x="0" y="0" width="640" height="{height}" fill="#220000"/>\n'
        f'  <g id="unique000">\n'
        f'    <path d="M 0 0 L 640 0 L 640 {height} L 0 {height} Z" '
        f'fill="#ff5555"/>\n'
        f'    <text x="4" y="14" font-family="monospace" font-size="11" '
        f'fill="white">{tspans}</text>\n'
        f'  </g>\n'
        f'</svg>\n'
    )
    try:
        with open(svg_path, "w", encoding="utf-8") as f:
            f.write(svg)
    except OSError:
        pass


def _convert_output_to_svg(input_path, svg_path):
    """Convert pdftex output (PDF) to SVG with embedded rendered image.

    Uses the Swift LaTeXEngine via a signal file, or falls back to
    writing the PDF path for Swift to pick up on next frame.
    """
    ext = os.path.splitext(input_path)[1].lower()

    # Write a signal file that Swift's LaTeXEngine can pick up
    signal_dir = os.path.join(tempfile.gettempdir(), "latex_signals")
    os.makedirs(signal_dir, exist_ok=True)
    signal_file = os.path.join(signal_dir, "compile_request.txt")

    with open(signal_file, 'w') as f:
        f.write(f"{input_path}\n{svg_path}\n")

    # Wait briefly for Swift to process (it runs on its own queue)
    import time
    for _ in range(20):  # Wait up to 2 seconds
        if os.path.exists(svg_path) and os.path.getsize(svg_path) > 50:
            print(f"[latex] SVG created by Swift engine: {svg_path}")
            return True
        time.sleep(0.1)

    # Swift didn't process it — try to create SVG ourselves
    # For PDF: create an SVG that references the PDF (manim can't use this directly)
    # For DVI: we'd need dvisvgm
    print(f"[latex] Swift engine didn't produce SVG, falling back")
    return False


def _render_with_cairo(expression, svg_path):
    """Render LaTeX expression to SVG (fallback when pdftex isn't used).

    Produces an SVG where each character is wrapped in its own
    ``<g id="uniqueNNN">`` group. This naming convention is what manim's
    MathTex SVG parser looks for via `\\special{…}` markers when reading
    dvisvgm's output — without these groups manim prints hundreds of
    "Could not find SVG group for tex part N (id: unique000)" errors
    and falls back to the root group.

    Each character is emitted as an SVG ``<path>`` element built from
    Cairo's ``text_path()`` glyph outlines. manim uses the ``svgelements``
    library to parse SVGs, and that library only supports ``<path>`` /
    ``<rect>`` / ``<circle>`` / etc. — it rejects ``<text>`` with
    ``WARNING Unsupported element type: <class 'svgelements.svgelements.Text'>``
    and silently drops the glyph. So we pre-convert the text to vector
    paths here.
    """
    import re

    display = expression
    # LaTeX → Unicode conversion for common math symbols
    display = re.sub(r'\\frac\{([^}]*)\}\{([^}]*)\}', r'(\1)/(\2)', display)
    display = re.sub(r'\\sqrt\{([^}]*)\}', r'√(\1)', display)
    _greek = {
        'alpha': 'α', 'beta': 'β', 'gamma': 'γ', 'delta': 'δ', 'epsilon': 'ε',
        'zeta': 'ζ', 'eta': 'η', 'theta': 'θ', 'iota': 'ι', 'kappa': 'κ',
        'lambda': 'λ', 'mu': 'μ', 'nu': 'ν', 'xi': 'ξ', 'pi': 'π', 'rho': 'ρ',
        'sigma': 'σ', 'tau': 'τ', 'upsilon': 'υ', 'phi': 'φ', 'chi': 'χ',
        'psi': 'ψ', 'omega': 'ω',
        'Gamma': 'Γ', 'Delta': 'Δ', 'Theta': 'Θ', 'Lambda': 'Λ', 'Xi': 'Ξ',
        'Pi': 'Π', 'Sigma': 'Σ', 'Upsilon': 'Υ', 'Phi': 'Φ', 'Psi': 'Ψ',
        'Omega': 'Ω',
    }
    for name, sym in _greek.items():
        display = display.replace(f'\\{name}', sym)
    display = re.sub(r'\\(sin|cos|tan|log|ln|exp|lim|min|max|sup|inf|arg)\b', r'\1', display)
    display = display.replace('\\cdot', '·').replace('\\times', '×').replace('\\div', '÷').replace('\\pm', '±').replace('\\mp', '∓')
    display = display.replace('\\infty', '∞').replace('\\neq', '≠').replace('\\approx', '≈').replace('\\sim', '∼').replace('\\equiv', '≡')
    display = display.replace('\\leq', '≤').replace('\\geq', '≥').replace('\\ll', '≪').replace('\\gg', '≫')
    display = display.replace('\\int', '∫').replace('\\oint', '∮').replace('\\sum', 'Σ').replace('\\prod', '∏')
    display = display.replace('\\partial', '∂').replace('\\nabla', '∇')
    display = display.replace('\\rightarrow', '→').replace('\\to', '→').replace('\\leftarrow', '←')
    display = display.replace('\\Rightarrow', '⇒').replace('\\Leftarrow', '⇐').replace('\\iff', '⇔')
    display = display.replace('\\in', '∈').replace('\\notin', '∉').replace('\\subset', '⊂').replace('\\subseteq', '⊆')
    display = display.replace('\\cup', '∪').replace('\\cap', '∩').replace('\\emptyset', '∅')
    display = display.replace('\\forall', '∀').replace('\\exists', '∃')
    display = display.replace('\\left', '').replace('\\right', '')
    display = re.sub(r'\\[a-zA-Z]+\{([^}]*)\}', r'\1', display)
    display = re.sub(r'\\[a-zA-Z]+', '', display)
    display = re.sub(r'[\$\{\}\\]', '', display).strip() or "?"
    display = re.sub(r'\s+', ' ', display)

    # Font size chosen so the resulting SVG coordinate range lands in a
    # similar scale to what dvisvgm emits from a 12pt LaTeX document —
    # manim's MathTex auto-normalizer then produces mobjects of roughly
    # the right on-screen size. Too big here → MathTex fills the screen;
    # too small → MathTex is a dot.
    fs = 20

    # Glyph rendering style. Values:
    #   outline — full Cairo glyph outlines via copy_path(); 50–200
    #             VMobject points per character. Prettiest but heaviest;
    #             long scenes hit the 16 GB jetsam limit around
    #             animation ~20.
    #   coarse  — Cairo copy_path_flat() with a high tolerance so curves
    #             become a handful of line segments; visible characters
    #             at ~15–40 VMobject points per glyph (~5× lighter than
    #             outline). Default on iOS.
    #   rect    — one bounding-box rectangle per character (~16 points).
    #             Math shows as blocks but extremely cheap.
    #   empty   — zero geometry; math invisible.
    _style = os.environ.get("OFFLINAI_LATEX_GLYPH_STYLE", "").strip().lower()
    if not _style:
        # outline now works on iOS: the real memory hog was manim's
        # animation cache JSON-serializing every mobject on every
        # play() call (disabled by default on iOS in manim._config).
        _style = "outline"

    # Try Cairo for real glyph paths — gives proper vector output that
    # manim's SVG parser can turn into per-character VMobjects.
    try:
        import cairo
        os.makedirs(os.path.dirname(svg_path) or '.', exist_ok=True)

        # Dedicated context for path extraction. We reuse it and call
        # new_path() between characters to clear the accumulated path.
        path_surface = cairo.ImageSurface(cairo.FORMAT_ARGB32, 1, 1)
        pctx = cairo.Context(path_surface)
        pctx.select_font_face("sans-serif", cairo.FONT_SLANT_NORMAL, cairo.FONT_WEIGHT_NORMAL)
        pctx.set_font_size(fs)

        # Font-level metrics drive the vertical canvas extent so glyphs
        # with descenders (g, p, ρ, γ, μ) don't get clipped below the
        # baseline.
        font_ext = pctx.font_extents()
        ascent = font_ext[0]
        descent = font_ext[1]

        # Constants defined in pycairo's `cairo` module (PATH_MOVE_TO = 0,
        # PATH_LINE_TO = 1, PATH_CURVE_TO = 2, PATH_CLOSE_PATH = 3). We
        # look them up dynamically in case the build uses a different enum.
        PATH_MOVE_TO = cairo.PATH_MOVE_TO
        PATH_LINE_TO = cairo.PATH_LINE_TO
        PATH_CURVE_TO = cairo.PATH_CURVE_TO
        PATH_CLOSE_PATH = cairo.PATH_CLOSE_PATH

        # ── Pass 1: lay out each glyph, extract its path data ──────
        # Baseline is at y=0. Glyphs above baseline have negative y, below
        # baseline have positive y. We'll translate the final SVG so the
        # whole thing sits inside a positive viewBox.
        layout = []  # [(idx, path_d_string), ...]
        x = 0.0
        baseline_y = 0.0

        for i, ch in enumerate(display):
            te = pctx.text_extents(ch)
            adv = te.x_advance

            # Whitespace / unhittable glyphs — emit empty group so
            # manim's mathtex[i] indexing stays aligned with `display[i]`.
            if not ch.strip() or (adv <= 0 and te.width <= 0):
                # Space still consumes horizontal room even with no glyph.
                layout.append((i, None))
                x += (adv if adv > 0 else fs * 0.3)
                continue

            if _style == "empty":
                layout.append((i, None))
                x += adv
                continue

            if _style == "rect":
                # Simple 4-corner rectangle matching the glyph's ink
                # bounding box. 4 line segments → ~16 VMobject points
                # (vs 50–200 for the outline path), and the rectangles
                # clearly indicate where math characters live.
                rx = x + te.x_bearing
                ry = baseline_y + te.y_bearing
                rw = te.width if te.width > 0 else adv * 0.8
                rh = te.height if te.height > 0 else fs * 0.6
                d = (
                    f'M{rx:.2f} {ry:.2f} '
                    f'L{rx + rw:.2f} {ry:.2f} '
                    f'L{rx + rw:.2f} {ry + rh:.2f} '
                    f'L{rx:.2f} {ry + rh:.2f} Z'
                )
                layout.append((i, d))
                x += adv
                continue

            # _style == "outline" or "coarse": extract glyph path.
            #   outline → copy_path() (preserves curves; rich detail).
            #   coarse  → copy_path_flat() with a high tolerance so
            #             each curve becomes 1–3 line segments.
            pctx.new_path()
            if _style == "coarse":
                # Cairo tolerance is the maximum allowable error in
                # device units between the real curve and its line
                # approximation. Default is 0.1. We set it much higher
                # so each glyph produces ~10–30 line segments instead
                # of the ~100 that outline mode would.
                pctx.set_tolerance(fs * 0.25)
            pctx.move_to(x, baseline_y)
            try:
                pctx.text_path(ch)
            except Exception:
                layout.append((i, None))
                x += adv
                continue

            try:
                if _style == "coarse":
                    path_data = pctx.copy_path_flat()
                else:
                    path_data = pctx.copy_path()
            except Exception:
                path_data = []

            d_parts = []
            for entry in path_data:
                ptype, pts = entry[0], entry[1]
                if ptype == PATH_MOVE_TO:
                    d_parts.append(f'M{pts[0]:.2f} {pts[1]:.2f}')
                elif ptype == PATH_LINE_TO:
                    d_parts.append(f'L{pts[0]:.2f} {pts[1]:.2f}')
                elif ptype == PATH_CURVE_TO:
                    d_parts.append(
                        f'C{pts[0]:.2f} {pts[1]:.2f} '
                        f'{pts[2]:.2f} {pts[3]:.2f} '
                        f'{pts[4]:.2f} {pts[5]:.2f}'
                    )
                elif ptype == PATH_CLOSE_PATH:
                    d_parts.append('Z')

            d = ' '.join(d_parts) if d_parts else None
            layout.append((i, d))
            x += adv

        total_advance = x

        # ── Compute the real bounding box ─────────────────────────
        # Cairo's font_extents.ascent / .descent are positive distances
        # from the baseline. In our coord system (baseline at y=0), the
        # content spans roughly [-ascent, +descent] vertically.
        pad = 2.0
        min_x = -pad
        min_y = -ascent - pad
        max_x = total_advance + pad
        max_y = descent + pad

        vb_x = min_x
        vb_y = min_y
        vb_w = max(max_x - min_x, 1.0)
        vb_h = max(max_y - min_y, 1.0)

        # Version marker lets the manim-side cache invalidator detect
        # stale SVGs from previous offlinai_latex builds. v6 restores
        # full outline quality on iOS after disabling manim's animation
        # cache (the real memory bottleneck on long MathTex scenes).
        parts = [
            f'<!--offlinai_latex v7 style={_style}-->',
            f'<svg xmlns="http://www.w3.org/2000/svg" '
            f'width="{vb_w:.2f}" height="{vb_h:.2f}" '
            f'viewBox="{vb_x:.2f} {vb_y:.2f} {vb_w:.2f} {vb_h:.2f}" '
            f'fill="white">'
        ]

        for (i, d) in layout:
            if d:
                parts.append(
                    f'<g id="unique{i:03d}">'
                    f'<path d="{d}" fill="white" fill-rule="evenodd"/>'
                    f'</g>'
                )
            else:
                parts.append(f'<g id="unique{i:03d}"/>')

        parts.append('</svg>')
        path_surface.finish()

        with open(svg_path, 'w', encoding='utf-8') as f:
            f.write(''.join(parts))
    except ImportError:
        # No Cairo — emit a minimal <path> stroke placeholder so
        # svgelements has something to parse and manim's unique000
        # lookup doesn't error. The v3 marker keeps this file from
        # being invalidated by the manim-side cache check.
        w = max(len(display) * fs * 0.5, 30)
        h = fs * 1.2
        svg = (
            '<!--offlinai_latex v3-->'
            f'<svg xmlns="http://www.w3.org/2000/svg" '
            f'width="{w:.1f}" height="{h:.1f}" '
            f'viewBox="0 0 {w:.1f} {h:.1f}">'
            f'<g id="unique000">'
            f'<path d="M0 {h*0.7:.1f} L{w:.1f} {h*0.7:.1f}" '
            f'stroke="white" stroke-width="1" fill="none"/>'
            f'</g>'
            f'</svg>'
        )
        os.makedirs(os.path.dirname(svg_path) or '.', exist_ok=True)
        with open(svg_path, 'w', encoding='utf-8') as f:
            f.write(svg)
